package com.chaobo.scm.supplier.infrastructure.persistence.asn;import org.apache.ibatis.annotations.*;import java.time.OffsetDateTime;import java.util.*;
@Mapper public interface AsnTransportPerformanceMapper {record Row(long asnId,OffsetDateTime shippedAt,OffsetDateTime arrivedAt,long transitMinutes){}@Select("SELECT a.asn_id asnId,a.ship_at shippedAt,MIN(t.occurred_at) arrivedAt,TIMESTAMPDIFF(MINUTE,a.ship_at,MIN(t.occurred_at)) transitMinutes FROM sup_asn a JOIN sup_asn_transport_trail t ON t.asn_id=a.asn_id AND t.transport_status=3 WHERE a.supplier_id=#{supplierId} AND a.ship_at IS NOT NULL AND t.occurred_at&gt;=#{from} AND t.occurred_at&lt;#{to} GROUP BY a.asn_id,a.ship_at ORDER BY arrivedAt DESC")List<Row> arrived(@Param("supplierId")long supplierId,@Param("from")OffsetDateTime from,@Param("to")OffsetDateTime to);}
